import { create } from 'zustand'

const useSplitStore = create((set) => ({
    plans: null,
    totalAmount: null,
    installments: null,
    selectedPlan: null,
    setPlans: (allPlans) => set(() => ({
        plans: [...allPlans]
    })),
    setTotalAmount: (amount) => set(() => ({
        totalAmount: amount
    })),
    setInstallments: (installments) => set(() => ({
        installments
    })),
    setSelectedPlan: (selectedPlan) => set(() => ({
        selectedPlan
    }))
}))

export default useSplitStore
